// Holt eine URL und extrahiert lesbaren Text (Tags/Skripte entfernt).
async function run(input) {
  const url = String((input && input.url) || '');
  if (!/^https?:\/\//.test(url)) return { fehler: 'Bitte eine vollstaendige http(s)-URL angeben.' };
  const res = await fetch(url, { headers: { 'user-agent': 'Astoris-AddOn/1.0' } });
  if (!res.ok) return { fehler: 'HTTP ' + res.status };
  let html = await res.text();
  html = html.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '');
  const title = ((html.match(/<title>([\s\S]*?)<\/title>/i) || [])[1] || '').trim();
  let text = html.replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ').trim();
  if (text.length > 6000) text = text.slice(0, 6000) + ' [gekuerzt]';
  return { titel: title, text: text, zeichen: text.length, url: url };
}
